        KeEnterCriticalRegion();
        ExAcquirePushLockExclusiveEx(VidMmGlobalAllocFromOwner + 344, 0);
        v68 = 1;                                                             // this call acquired
        *(VidMmGlobalAllocFromOwner + 352) = KeGetCurrentThread();           // owner tag at +0x160
    }
    // ... work ...
